Rules.InvariantScript:
With(
    {
        sortedData: Sort(
            Sort(
                Filter(
                    'UK Customs SharePoint Order Confirmation List',
                    'Patient UID' = CurrentOrderItem.'Patient UID Lookup'.Value,'OC Input'=true
                ),

                'Filter Order',// Sort by this column
                SortOrder.Ascending
            ),
            Created,
            SortOrder.Ascending
        )
    },
    ForAll(
        Sequence(CountRows(sortedData)),
        Patch(
            Last(
                FirstN(
                    sortedData,
                    Value
                )
            ),
            {RowNumber: Value}
        )
    )
)

